import{_ as i,o as a,c as t,a2 as o}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"2024年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2024年/核心总结.md","filePath":"01_letters/2024年/核心总结.md"}'),e={name:"01_letters/2024年/核心总结.md"};function r(u,l,n,s,h,q){return a(),t("div",null,[...l[0]||(l[0]=[o('<h1 id="_2024年巴菲特致股东信核心总结" tabindex="-1">2024年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2024年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2024年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="巴菲特的坦诚与反思" tabindex="-1">巴菲特的坦诚与反思 <a class="header-anchor" href="#巴菲特的坦诚与反思" aria-label="Permalink to &quot;巴菲特的坦诚与反思&quot;">​</a></h2><ul><li>2019-2023年致股东信中16次使用&quot;错误&quot;或&quot;失误&quot;一词；同期许多大公司从未使用过</li><li>强调CEO对股东的&quot;报告&quot;义务：坦承错误是责任，愚弄股东最终是愚弄自己</li><li>94岁的巴菲特确认格雷格·阿贝尔将接任CEO并继续撰写致股东信</li><li>选人标准：从不看候选人上过什么学校，&quot;很大一部分商业才能是天生的&quot;</li></ul><h2 id="皮特·利格-天生的商业奇才" tabindex="-1">皮特·利格：天生的商业奇才 <a class="header-anchor" href="#皮特·利格-天生的商业奇才" aria-label="Permalink to &quot;皮特·利格：天生的商业奇才&quot;">​</a></h2><ul><li>森林河公司创始人，2005年以10万美元年薪+业绩分成10%的薪酬方案将公司卖给伯克希尔</li><li>此后19年表现惊人，竞争对手无人能及</li><li>巴菲特认为他是&quot;天生的商业奇才&quot;，教育背景远不如天赋重要</li><li>2024年11月去世，享年80岁</li></ul><h2 id="经营业绩" tabindex="-1">经营业绩 <a class="header-anchor" href="#经营业绩" aria-label="Permalink to &quot;经营业绩&quot;">​</a></h2><ul><li><strong>经营收益</strong>：2024年474亿美元（2023年374亿美元，增长27%）</li><li>189家运营企业中53%报告收益下降，但保险和投资收益大幅弥补</li><li>GEICO在托德·科姆斯操刀下五年重塑，2024年改善惊人</li><li>公用事业持股从约92%增至100%，代价约39亿美元</li></ul><h2 id="破纪录的纳税" tabindex="-1">破纪录的纳税 <a class="header-anchor" href="#破纪录的纳税" aria-label="Permalink to &quot;破纪录的纳税&quot;">​</a></h2><ul><li>2024年向美国国税局支付<strong>268亿美元</strong>联邦企业所得税，约占全美企业纳税总额的5%</li><li>相当于全年每20分钟送出一张100万美元支票，年底仍欠税</li><li>伯克希尔60年仅支付过一次现金股息（1967年，每股10美分），所有利润持续再投资</li><li>历史累计联邦所得税超过1010亿美元</li></ul><h2 id="资本配置哲学" tabindex="-1">资本配置哲学 <a class="header-anchor" href="#资本配置哲学" aria-label="Permalink to &quot;资本配置哲学&quot;">​</a></h2><ul><li>资金大部分配置在股票上——主要是美国股票，而非现金</li><li>2024年可流通股票持仓从3540亿美元降至2720亿美元，但非上市企业价值增加且远大于股票组合</li><li>&quot;伯克希尔永远不会偏好持有现金等价物而不是拥有好企业&quot;</li><li>好企业和有才能的个人通常能找到应对货币不稳定的方法</li></ul><h2 id="保险业务-核心引擎" tabindex="-1">保险业务：核心引擎 <a class="header-anchor" href="#保险业务-核心引擎" aria-label="Permalink to &quot;保险业务：核心引擎&quot;">​</a></h2><ul><li>财产险/意外险是伯克希尔的核心业务，拥有独特的&quot;先收钱、后赔付&quot;财务模式</li><li><strong>浮存金</strong>从20年前的460亿美元增长至<strong>1710亿美元</strong></li><li>过去20年承保利润320亿美元（税后，约占销售额3.3%），浮存金几乎零成本</li><li>在阿吉特·贾因领导下成为全球风险承担能力的标杆</li><li>不依赖再保险公司，具有实质性的成本优势</li></ul><h2 id="日本投资持续加码" tabindex="-1">日本投资持续加码 <a class="header-anchor" href="#日本投资持续加码" aria-label="Permalink to &quot;日本投资持续加码&quot;">​</a></h2><ul><li>五大商社（伊藤忠、丸红、三菱、三井、住友）持股成本138亿美元，市值235亿美元</li><li>预计2025年股息收入约8.12亿美元，日元债务利息成本仅约1.35亿美元</li><li>用日元计价固定利率债务对冲汇率风险</li><li>五家公司的资本配置、管理层和对投资者态度令巴菲特钦佩</li><li>高管薪酬远不如美国同行激进，持续回购股票</li></ul><h2 id="长期业绩" tabindex="-1">长期业绩 <a class="header-anchor" href="#长期业绩" aria-label="Permalink to &quot;长期业绩&quot;">​</a></h2><ul><li><strong>1965-2024年复合年增长率</strong>：伯克希尔19.9% vs 标普500 10.4%</li><li><strong>1964-2024年总体增长</strong>：伯克希尔5,502,284% vs 标普500 39,054%</li><li>伯克希尔60年投资美国的故事：&quot;公司死亡的原因有很多，但衰老本身并不是致命的。今天的伯克希尔比1965年要年轻得多。&quot;</li></ul><h2 id="关键金句" tabindex="-1">关键金句 <a class="header-anchor" href="#关键金句" aria-label="Permalink to &quot;关键金句&quot;">​</a></h2><ul><li>&quot;错误会逐渐消退；成功的决策可以永远绽放光彩。&quot;</li><li>&quot;除了美国，伯克希尔不可能在任何地方取得其成就；而美国如果没有伯克希尔，其成功程度将与现在完全一样。&quot;</li><li>&quot;财产险/意外险保险是艺术也是科学，绝不是乐观主义者的业务。&quot;</li><li>&quot;如果不支付股息、持续再投资，复利的魔力会创造超出任何人想象的奇迹。&quot;</li></ul>',19)])])}const _=i(e,[["render",r]]);export{c as __pageData,_ as default};
